import pandas as pd
import matplotlib.pyplot as plt

#################################################################################################################################################################
######################## This file graphs up the resulting csv files generated by poker predict after they have been cleaned by clean.py ########################
#################################################################################################################################################################

# -----------------------------
# Utility: create heatmap
# -----------------------------
def create_heatmap(df, value_col, title, filename):
    c_vals = sorted(df["C"].unique())
    e_vals = sorted(df["epsilon"].unique())

    pivot = df.pivot(index="epsilon", columns="C", values=value_col)
    pivot = pivot.reindex(index=e_vals, columns=c_vals)

    plt.figure(figsize=(7,6))
    plt.imshow(pivot.values, aspect="auto")

    plt.xticks(range(len(pivot.columns)), pivot.columns)
    plt.yticks(range(len(pivot.index)), pivot.index)

    plt.xlabel("C")
    plt.ylabel("epsilon")
    plt.title(title)

    for i in range(pivot.shape[0]):
        for j in range(pivot.shape[1]):
            plt.text(j, i, f"{pivot.iloc[i,j]:.4f}",
                     ha="center", va="center", fontsize=8)

    plt.colorbar()
    plt.tight_layout()
    plt.savefig(filename)
    plt.close()


# -----------------------------
# SVR Heatmaps
# -----------------------------
def svr_heatmaps(prefix):

    # Linear
    df = pd.read_csv(f"{prefix}_svr_linear_scores.csv")
    create_heatmap(df,"avg_score",f"{prefix} SVR Linear Avg Score",
                   f"{prefix}_svr_linear_avg_heatmap.png")
    create_heatmap(df,"max_score",f"{prefix} SVR Linear Max Score",
                   f"{prefix}_svr_linear_max_heatmap.png")

    # Sigmoid
    df = pd.read_csv(f"{prefix}_svr_sigmoid_scores.csv")
    create_heatmap(df,"avg_score",f"{prefix} SVR Sigmoid Avg Score",
                   f"{prefix}_svr_sigmoid_avg_heatmap.png")
    create_heatmap(df,"max_score",f"{prefix} SVR Sigmoid Max Score",
                   f"{prefix}_svr_sigmoid_max_heatmap.png")

    # Polynomial
    df = pd.read_csv(f"{prefix}_svr_poly_scores.csv")
    for degree in sorted(df["degree"].unique()):
        sub = df[df["degree"] == degree]

        create_heatmap(sub,"avg_score",
            f"{prefix} SVR Polynomial Avg Score",
            f"{prefix}_svr_poly_deg{degree}_avg.png")

        create_heatmap(sub,"max_score",
            f"{prefix} SVR Polynomial Max Score",
            f"{prefix}_svr_poly_deg{degree}_max.png")

    # RBF
    df = pd.read_csv(f"{prefix}_svr_rbf_scores.csv")
    for gamma in sorted(df["gamma"].unique()):
        sub = df[df["gamma"] == gamma]

        create_heatmap(sub,"avg_score",
            f"{prefix} SVR RBF Avg Score",
            f"{prefix}_svr_rbf_gamma{gamma}_avg.png")

        create_heatmap(sub,"max_score",
            f"{prefix} SVR RBF Max Score",
            f"{prefix}_svr_rbf_gamma{gamma}_max.png")


# -----------------------------
# KPCA Charts
# -----------------------------
def kpca_chart(prefix):

    components = [10,15,20]

    rf_scores = []
    svr_scores = []

    for c in components:
        rf = pd.read_csv(f"{prefix}_KPCA_{c}_random_forest_regressor.csv")
        svr = pd.read_csv(f"{prefix}_KPCA_{c}_svr_linear_scores.csv")

        rf_scores.append(rf["avg_score"].max())
        svr_scores.append(svr["avg_score"].max())

    plt.figure(figsize=(7,5))

    plt.plot(components,rf_scores,marker="o",label="Random Forest 100 Trees")
    plt.plot(components,svr_scores,marker="o",label="SVR Linear")

    plt.xlabel("KPCA Components")
    plt.ylabel("Best Avg Score")
    plt.title(f"{prefix} KPCA Comparison")

    plt.xticks(components)
    plt.legend()
    plt.tight_layout()

    plt.savefig(f"{prefix}_kpca_comparison.png")
    plt.close()

def plot_random_forest_tree_scores(prefix):
    import pandas as pd
    import matplotlib.pyplot as plt

    file = f"{prefix}_random_forest_regressor.csv"

    df = pd.read_csv(file)

    # ensure order 100 -> 1000 -> 10000
    df = df.sort_values("num_trees")

    trees = df["num_trees"].astype(str)

    # -----------------------------
    # Trees vs Average Score
    # -----------------------------
    plt.figure(figsize=(7,5))

    plt.bar(trees, df["avg_score"])

    plt.xlabel("Number of Trees")
    plt.ylabel("Average Score")

    # scale axis to data
    ymin = df["avg_score"].min()
    ymax = df["avg_score"].max()
    padding = (ymax - ymin) * 0.1
    plt.ylim(ymin - padding, ymax + padding)

    plt.tight_layout()
    plt.savefig(f"{prefix}_trees_vs_avg_score.png")
    plt.close()

    # -----------------------------
    # Trees vs Max Score
    # -----------------------------
    plt.figure(figsize=(7,5))

    plt.bar(trees, df["max_score"])

    plt.xlabel("Number of Trees")
    plt.ylabel("Max Score")

    ymin = df["max_score"].min()
    ymax = df["max_score"].max()
    padding = (ymax - ymin) * 0.1
    plt.ylim(ymin - padding, ymax + padding)

    plt.tight_layout()
    plt.savefig(f"{prefix}_trees_vs_max_score.png")
    plt.close()


def load_svr_bargraph_data(prefix):
    import pandas as pd

    rows = []

    # Linear
    df = pd.read_csv(f"{prefix}_svr_linear_scores.csv")
    df = df[(df["avg_score"] >= 0) & (df["max_score"] >= 0)]
    for _, row in df.iterrows():
        rows.append({
            "group": f"{prefix}\nlinear",
            "config": f"C={row['C']}, e={row['epsilon']}",
            "avg_score": row["avg_score"],
            "max_score": row["max_score"]
        })

    # Sigmoid
    df = pd.read_csv(f"{prefix}_svr_sigmoid_scores.csv")
    df = df[(df["avg_score"] >= 0) & (df["max_score"] >= 0)]
    for _, row in df.iterrows():
        rows.append({
            "group": f"{prefix}\nsigmoid",
            "config": f"C={row['C']}, e={row['epsilon']}",
            "avg_score": row["avg_score"],
            "max_score": row["max_score"]
        })

    # Polynomial
    df = pd.read_csv(f"{prefix}_svr_poly_scores.csv")
    df = df[(df["avg_score"] >= 0) & (df["max_score"] >= 0)]
    for _, row in df.iterrows():
        rows.append({
            "group": f"{prefix}\npoly d={int(row['degree'])}",
            "config": f"C={row['C']}, e={row['epsilon']}",
            "avg_score": row["avg_score"],
            "max_score": row["max_score"]
        })

    # RBF
    df = pd.read_csv(f"{prefix}_svr_rbf_scores.csv")
    df = df[(df["avg_score"] >= 0) & (df["max_score"] >= 0)]
    for _, row in df.iterrows():
        rows.append({
            "group": f"{prefix}\nrbf g={row['gamma']}",
            "config": f"C={row['C']}, e={row['epsilon']}",
            "avg_score": row["avg_score"],
            "max_score": row["max_score"]
        })

    return pd.DataFrame(rows)

def plot_all_svr_bargraphs():
    import pandas as pd
    import matplotlib.pyplot as plt
    import numpy as np

    bet_df = load_svr_bargraph_data("bet_predictor")
    card_df = load_svr_bargraph_data("card_predictor")

    df = pd.concat([bet_df, card_df], ignore_index=True)

    groups = sorted(df["group"].unique())

    # order configs by C then epsilon
    def parse_config(config):
        c, e = config.replace("C=","").replace("e=","").split(", ")
        return float(c), float(e)

    configs = sorted(df["config"].unique(), key=parse_config)

    x = np.arange(len(groups))
    width = 0.8 / len(configs)

    def make_graph(score_col, filename, ylabel):

        plt.figure(figsize=(18,8))

        for i, config in enumerate(configs):
            heights = []

            for g in groups:
                match = df[(df["group"] == g) & (df["config"] == config)]
                if len(match) == 0:
                    heights.append(np.nan)
                else:
                    heights.append(match.iloc[0][score_col])

            plt.bar(
                x + (i - len(configs)/2) * width,
                heights,
                width,
                label=config
            )

        plt.xticks(x, groups, rotation=45, ha="right")
        plt.ylabel(ylabel)
        plt.xlabel("Kernel")
        plt.legend(title="C / epsilon", bbox_to_anchor=(1.02,1))
        plt.tight_layout()

        plt.savefig(filename)
        plt.close()

    make_graph("avg_score", "svr_avg_score_bargraph.png", "Average Score")
    make_graph("max_score", "svr_max_score_bargraph.png", "Max Score")


def plot_feature_histograms():
    import pandas as pd
    import matplotlib.pyplot as plt
    import glob

    # Full feature lists
    card_features = [
        "n_players","bet_total","flop_board_strength","turn_board_strength","river_board_strength",
        "flop_0","flop_1","flop_2","flop_3","flop_4","flop_5","flop_6","flop_7","flop_8",
        "turn_0","turn_1","turn_2","turn_3","turn_4","turn_5","turn_6","turn_7","turn_8",
        "river_0","river_1","river_2","river_3","river_4","river_5","river_6","river_7","river_8"
    ]

    bet_features = [
        "n_players","flop_strength","turn_strength","river_strength",
        "flop_board_strength","turn_board_strength","river_board_strength",
        "rank1","suit1","rank2","suit2",
        "flop_0","flop_1","flop_2","flop_3","flop_4","flop_5","flop_6","flop_7","flop_8",
        "turn_0","turn_1","turn_2","turn_3","turn_4","turn_5","turn_6","turn_7","turn_8",
        "river_0","river_1","river_2","river_3","river_4","river_5","river_6","river_7","river_8"
    ]

    files = glob.glob("*features.csv")

    for file in files:

        df = pd.read_csv(file)

        # determine which feature list to use
        if "card_predictor" in file:
            feature_list = card_features
        else:
            feature_list = bet_features

        # count occurrences
        counts = df.sum()

        # ensure missing features appear with 0
        counts = counts.reindex(feature_list, fill_value=0)

        # sort so graph is readable
        counts = counts.sort_values(ascending=False)

        plt.figure(figsize=(16,6))

        plt.bar(counts.index, counts.values)

        plt.xticks(rotation=90)
        plt.xlabel("Feature")
        plt.ylabel("Occurrences")

        plt.tight_layout()

        output = file.replace(".csv", "_histogram.png")
        plt.savefig(output)
        plt.close()


# -----------------------------
# Run everything
# -----------------------------
svr_heatmaps("bet_predictor")
svr_heatmaps("card_predictor")

kpca_chart("bet_predictor")
kpca_chart("card_predictor")

plot_random_forest_tree_scores("bet_predictor")
plot_random_forest_tree_scores("card_predictor")
plot_all_svr_bargraphs()

plot_feature_histograms()



print("All graphs generated.")
